"use client";

import { cn } from "@/lib/utils";

export default function Beam({
  children,
  className,
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <div className={cn("relative w-full", className)}>
      <div className="relative min-h-[31.25rem] w-full bg-transparent">
        <div
          className={cn(
            "absolute left-1/2 -top-[9.375rem] lg:-top-[4rem] -z-10 -translate-x-1/2 blur-[6.25rem]",
            "h-0 w-0",
            "border-l-[600px] lg:border-l-[700px] xl:border-l-[400px] border-l-transparent",
            "border-r-[600px] lg:border-r-[700px] xl:border-l-[400px] border-r-transparent",
            "border-t-[600px] lg:border-t-[700px] xl:border-l-[600px] border-t-[color:var(--orb-color-dark-fade)] dark:border-t-[color:var(--orb-color-dark)]"
          )}
        />

        <div
          className={cn(
            "absolute left-1/2 -translate-x-1/2 blur-[0.625rem]",
            "top-0 md:top-[2%]",
            "h-0 w-0",
            "border-l-[20rem] md:border-l-[35rem] lg:border-l-[25rem] border-l-transparent",
            "border-r-[20.75rem] md:border-r-[35.75rem] lg:border-r-[25.75rem] border-r-transparent",
            "border-t-[2.125rem] md:border-t-[3.125rem] lg:border-t-[2.125rem] border-t-white/80 dark:border-t-[rgba(255,255,255,0.2)]"
          )}
        />

        <div className="pt-20 md:pt-50 lg:pt-56">{children}</div>
      </div>
    </div>
  );
}

"use client";

import { motion } from "motion/react";
import { Button } from "@/components/ui/button";
import Transcriber from "./transcriber";

export default function Hero() {
  return (
    <div className="mx-2 md:mx-4 lg:mx-6 mt-24">
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.6 }}
        className="relative flex flex-col gap-16 md:gap-4 min-[1070px]:flex-row items-center min-[1070px]:justify-between lg:w-[95dvw] mx-auto pt-12 md:px-12 lg:pl-12 xl:pl-20 max-[348px]:h-225 max-[397px]:h-220 h-210 sm:h-204 min-[516px]:h-205  md:h-215 lg:h-250 xl:220 lg:min-h-full overflow-hidden rounded-4xl"
      >
        <motion.div
          initial={{ opacity: 0, scale: 1.1 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 1, ease: "easeOut" }}
          className="absolute inset-0 -z-10 bg-hero-radial-light dark:bg-hero-radial-dark 
             [--bg-pos:5%] lg:[--bg-pos:5%] 
             [--bg-mid:55%] md:[--bg-mid:45%] 
             [--bg-mid-alt:75%] lg:[--bg-mid-alt:70%]"
        />
        <section className="flex flex-col gap-4 z-10 text-center min-[1070px]:text-left items-center min-[1070px]:items-start 2xl:pl-28 3xl:pl-56 min-[1500px]:!pl-24 min-[1580px]:!pl-40 min-[1729px]:!pl-64 min-[2000px]:!pl-96 min-[2200px]:!pl-120 min-[2350px]:!pl-130 min-[2500px]:!pl-150">
          <motion.h1
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.2, ease: "easeOut" }}
            className="text-3xl md:text-[2.7rem] xl:text-5xl font-aleo"
          >
            Never Forget Another Call
          </motion.h1>
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.4, ease: "easeOut" }}
            className="text-base max-w-lg 4xl:text-2xl 4xl:max-w-3xl"
          >
            Record, transcribe, and take notes on your conversations— all in
            real-time. Turn every call into searchable, shareable insights.
          </motion.p>
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.6, ease: "easeOut" }}
          >
            <Button className="w-fit 4xl:text-2xl 4xl:px-6 4xl:h-16 hover:bg-white hover:text-foreground dark:hover:bg-secondary/80 dark:hover:text-foreground" size="lg">
              Start for free
            </Button>
          </motion.div>
        </section>
        <motion.section
          initial={{ opacity: 0, y: 50 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.5, ease: "easeOut" }}
          className="relative lg:mt-0 min-[1070px]:absolute min-[1070px]:right-10 xl:right-14 2xl:right-40 3xl:right-96 min-[1500px]:!right-24 min-[1629px]:!right-64 min-[2000px]:!right-96 min-[2200px]:!right-120 min-[2350px]:!right-130 min-[2500px]:!right-150 lg:-bottom-6 z-10 mt-7"
        >
          <Transcriber />
        </motion.section>
      </motion.div>
    </div>
  );
}

"use client";

import useCountdown from "@/hooks/use-countdown";
import {
  BatteryFullIcon,
  RotateCcwIcon,
  SignalHighIcon,
  WifiIcon,
  XIcon,
} from "lucide-react";
import { motion } from "motion/react";
import { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";

export default function Transcriber() {
  const { formatted, isRunning, toggle, reset } = useCountdown(0, true);
  const [barHeights, setBarHeights] = useState([48, 24, 32]);

  useEffect(() => {
    if (!isRunning) return;

    const interval = setInterval(() => {
      setBarHeights([
        Math.random() * 40 + 20,
        Math.random() * 40 + 20,
        Math.random() * 40 + 20,
      ]);
    }, 300);

    return () => clearInterval(interval);
  }, [isRunning]);

  return (
    <div className="w-full max-w-xs md:max-w-sm xl:max-w-md 4xl:max-w-2xl p-[1px] rounded-4xl bg-gradient-to-r from-primary/50 via-secondary/40 to-muted-foreground/20">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className="flex flex-col gap-2 md:gap-8 w-full bg-gradient-to-b from-background to-zinc-100 dark:to-muted dark:lg:to-neutral-950 rounded-4xl border-0 pb-6 md:pb-8"
      >
      <motion.section
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.2, duration: 0.4 }}
        className="flex flex-row items-center justify-between py-3 px-8"
      >
        <p className="text-xs md:text-base 4xl:text-2xl">9:41</p>
        <div className="flex flex-row items-center gap-1 md:gap-2">
          <motion.div
            initial={{ opacity: 0, scale: 0 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.3, duration: 0.3 }}
          >
            <SignalHighIcon className="w-4 h-4 md:w-6 md:h-6 4xl:w-8 4xl:h-8" />
          </motion.div>
          <motion.div
            initial={{ opacity: 0, scale: 0 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.4, duration: 0.3 }}
          >
            <WifiIcon className="w-4 h-4 md:w-6 md:h-6 4xl:w-8 4xl:h-8" />
          </motion.div>
          <motion.div
            initial={{ opacity: 0, scale: 0 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.5, duration: 0.3 }}
          >
            <BatteryFullIcon className="w-4 h-4 md:w-6 md:h-6 4xl:w-8 4xl:h-8" />
          </motion.div>
        </div>
      </motion.section>

      <div>
        <motion.section
          initial={{ scaleX: 0 }}
          animate={{ scaleX: 1 }}
          transition={{ delay: 0.4, duration: 0.5, ease: "easeOut" }}
          className="h-3 lg:h-4 4xl:h-6 w-72 lg:w-80 xl:w-100 4xl:w-150 mx-auto bg-muted-foreground/20 dark:bg-neutral-950 rounded-t-full origin-left"
        />

        <div className="flex flex-col gap-4 pt-12 lg:pt-18 dark:bg-muted/50 lg:dark:bg-neutral-950 px-6 md:px-8 rounded-t-4xl">
          <motion.section
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.6, duration: 0.5 }}
            className="flex flex-col gap-4 lg:gap-8"
          >
            <motion.p
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.7, duration: 0.4 }}
              className="text-2xl lg:text-4xl 4xl:text-5xl"
            >
              Call with Joanne
            </motion.p>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.9, duration: 0.4 }}
              className="flex items-center"
            >
              <motion.span
                animate={{ opacity: [1, 0, 1] }}
                transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                className="text-xl lg:text-3xl 4xl:text-4xl text-muted-foreground font-light opacity-80"
              >
                |
              </motion.span>
              <p className="text-xl lg:text-3xl 4xl:text-4xl text-muted-foreground font-light opacity-80">
                Write notes here.
              </p>
            </motion.div>
            <motion.p
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 0.8, y: 0 }}
              transition={{ delay: 1.1, duration: 0.4 }}
              className="text-muted-foreground text-sm md:text-base lg:text-lg 4xl:text-3xl"
            >
              Notio will keep transcribing even with your phone locked.
            </motion.p>
          </motion.section>

          <motion.section
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.8, duration: 0.5, ease: "easeOut" }}
            className="relative shadow-2xl rounded-2xl md:rounded-4xl bg-background flex flex-col gap-3 md:gap-4 4xl:gap-20 p-3 md:p-4 min-h-64 md:min-h-72 lg:min-h-85 xl:min-h-90 4xl:min-h-140 overflow-hidden"
          >
            <motion.div
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{
                opacity: isRunning ? 0.6 : 0.4,
                scale: isRunning ? [1, 1.05, 1] : 1,
              }}
              transition={{
                opacity: { duration: 0.4 },
                scale: { duration: 2, repeat: Infinity, ease: "easeInOut" },
              }}
              className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none w-20 h-20 md:w-32 md:h-32 4xl:w-[13rem] 4xl:h-[13rem]"
              style={{
                borderRadius: 232,
                background:
                  "radial-gradient(circle, var(--gradient-orb-base) 0%, var(--gradient-mid-light) 30%, var(--gradient-mid-dark) 60%, var(--gradient-end-light) 100%)",
                filter: "blur(40px)",
              }}
            />
            <div className="relative z-10 flex items-center justify-between">
              <motion.div whileTap={{ scale: 0.9 }} whileHover={{ scale: 1.1 }}>
                <Button
                  variant="outline"
                  size="icon"
                  className="rounded-full w-8 h-8 lg:w-10 lg:h-10 4xl:w-16 4xl:h-16"
                  onClick={reset}
                >
                  <motion.div
                    whileTap={{ rotate: -360 }}
                    transition={{ duration: 0.5 }}
                  >
                    <RotateCcwIcon className="w-4 h-4 lg:w-5 lg:h-5 4xl:w-8 4xl:h-8 4xl:size-10" />
                  </motion.div>
                </Button>
              </motion.div>
              <div className="flex flex-col items-center justify-center gap-1 lg:gap-2 4xl:gap-4">
                <motion.p
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 0.8 }}
                  transition={{ delay: 1, duration: 0.3 }}
                  className="text-xs md:text-sm font-light text-muted-foreground 4xl:text-2xl"
                >
                  +1 (555) 123-4567
                </motion.p>
                <motion.p
                  key={formatted}
                  initial={{ scale: 1 }}
                  transition={{ duration: 0.2 }}
                  className="text-lg md:text-2xl 4xl:text-4xl"
                >
                  {formatted}
                </motion.p>
              </div>
              <motion.div whileTap={{ scale: 0.9 }} whileHover={{ scale: 1.1 }}>
                <Button
                  variant="outline"
                  size="icon"
                  className="rounded-full w-8 h-8 lg:w-10 lg:h-10 4xl:w-16 4xl:h-16"
                >
                  <XIcon className="w-4 h-4 lg:w-5 lg:h-5 4xl:w-8 4xl:h-8 4xl:size-10" />
                </Button>
              </motion.div>
            </div>

            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ delay: 1, duration: 0.4 }}
              className="relative z-10 border border-foreground/20 rounded-full w-28 h-28 lg:w-40 lg:h-40 4xl:w-60 4xl:h-60 mx-auto flex items-center justify-center bg-background/50 backdrop-blur-sm"
            >
              <motion.button
                onClick={toggle}
                whileTap={{ scale: 0.9 }}
                className="relative w-8 h-8 lg:w-12 lg:h-12 4xl:w-16 4xl:h-16 bg-foreground flex items-center justify-center"
                animate={{ borderRadius: isRunning ? "4px" : "50%" }}
                transition={{ duration: 0.3, ease: "easeInOut" }}
              />
            </motion.div>

            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 1.2, duration: 0.4 }}
              className="relative z-10 flex items-center justify-center gap-2"
            >
              <motion.div
                animate={{ height: isRunning ? barHeights[0] * 0.7 : 34 }}
                transition={{ duration: 0.2, ease: "easeOut" }}
                className="w-1 lg:w-1.5 4xl:w-2 bg-muted-foreground rounded-sm"
              />
              <motion.div
                animate={{ height: isRunning ? barHeights[1] * 0.7 : 17 }}
                transition={{ duration: 0.2, ease: "easeOut" }}
                className="w-1 lg:w-1.5 4xl:w-2 bg-muted-foreground rounded-sm"
              />
              <motion.div
                animate={{ height: isRunning ? barHeights[2] * 0.7 : 22 }}
                transition={{ duration: 0.2, ease: "easeOut" }}
                className="w-1 lg:w-1.5 4xl:w-2 bg-muted-foreground rounded-sm"
              />
            </motion.div>
          </motion.section>
        </div>
      </div>
      </motion.div>
    </div>
  );
}

import { FeatureCardProps } from "@/types/components/feature";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import BlurredOrb from "@/components/blurred-orb";

export default function FeatureCard({
  feature,
}: {
  feature: FeatureCardProps;
}) {
  return (
    <Card key={feature.title} className="bg-background sm:max-w-xs min-h-96 4xl:max-w-xl 4xl:min-h-120 4xl:gap-8">
      <div className="flex items-center justify-center p-16 relative">
        <feature.icon size={32} className="4xl:size-12" />
        <BlurredOrb className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 blur-xl md:blur-2xl h-12 w-12 md:h-16 md:w-16 opacity-60 4xl:h-20 4xl:w-20 4xl:blur-2xl" />
      </div>
      <CardHeader>
        <CardTitle className="text-xl mx-auto 4xl:text-4xl">{feature.title}</CardTitle>
      </CardHeader>
      <CardContent>
        <CardDescription className="text-center opacity-80 4xl:text-2xl">
          {feature.description}
        </CardDescription>
      </CardContent>
    </Card>
  );
}

"use client";

import { FeatureCardProps } from "@/types/components/feature";
import { AudioLines, NotebookPen, Sparkle } from "lucide-react";
import { motion } from "motion/react";
import FeatureCard from "./feature-card";
import ToolFeature from "./tool-feature";
import TranscriptionFeature from "./transcription-feature";
export default function Features() {
  const features: FeatureCardProps[] = [
    {
      title: "Record your calls with ease",
      description:
        "Crystal-clear audio capture with automatic transcription. Never worry about missing details again.",
      icon: AudioLines,
    },
    {
      title: "Take notes as you talk",
      description:
        "Add highlights, action items, and reminders without interrupting the flow of conversation.",
      icon: NotebookPen,
    },
    {
      title: "Find any call in seconds",
      description:
        "Search transcripts, replay key moments, and export notes to your team—all in seconds.",
      icon: Sparkle,
    },
  ];

  return (
    <div className="flex flex-col gap-8 items-center justify-center p-4">
      <motion.h1
        initial={{ opacity: 0, y: 30 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true, margin: "-100px" }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className="text-3xl md:text-4xl 4xl:text-6xl font-aleo text-center"
      >
        One app for all your conversations
      </motion.h1>
      <motion.p
        initial={{ opacity: 0, y: 30 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true, margin: "-100px" }}
        transition={{ duration: 0.6, ease: "easeOut", delay: 0.1 }}
        className="text-lg text-center max-w-2xl text-muted-foreground 4xl:text-3xl 4xl:max-w-6xl"
      >
        Whether it&apos;s client meetings, interviews, or team calls—capture,
        organize, and review every conversation in one place.
      </motion.p>
      <section className="flex flex-wrap gap-4 md:gap-8 items-center justify-center max-md:pt-8">
        {features.map((feature, index) => (
          <motion.div
            key={feature.title}
            initial={{ opacity: 0, y: 40 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: "-50px" }}
            transition={{
              duration: 0.5,
              delay: 0.2 + index * 0.15,
              ease: "easeOut",
            }}
          >
            <FeatureCard feature={feature} />
          </motion.div>
        ))}
      </section>
      <ToolFeature />
      <TranscriptionFeature />
    </div>
  );
}

"use client";

import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { motion } from "motion/react";
import Image from "next/image";
import BlurredOrb from "@/components/blurred-orb";

type Tool = {
  name: string;
  lightImage: string;
  darkImage: string;
};

export default function ToolFeature() {
  const tools: Tool[] = [
    {
      name: "Loom",
      lightImage: "/logo/loom-mini-light.svg",
      darkImage: "/logo/loom-mini.svg",
    },
    {
      name: "Notion",
      lightImage: "/logo/notion-mini-light.svg",
      darkImage: "/logo/notion-mini.svg",
    },
    {
      name: "Medium",
      lightImage: "/logo/medium-light.svg",
      darkImage: "/logo/medium.svg",
    },
    {
      name: "Mailchip",
      lightImage: "/logo/mailchip-light.svg",
      darkImage: "/logo/mailchip.svg",
    },
    {
      name: "Calendly",
      lightImage: "/logo/calendly-light.svg",
      darkImage: "/logo/calendly.svg",
    },
  ];

  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-100px" }}
      transition={{ duration: 0.6, ease: "easeOut" }}
      className="w-full lg:py-20 4xl:py-32"
    >
      <Card className="w-full min-h-96 lg:gap-16 flex flex-col items-center justify-center dark:bg-background max-md:ring-0 dark:ring-1 shadow-none lg:py-18 4xl:gap-24">
        <CardHeader className="relative flex md:flex-wrap md:gap-12 items-center justify-center w-full justify-center">
          {tools.map((tool, index) => (
            <motion.div
              key={tool.name}
              initial={{ opacity: 0, scale: 0.8 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true, margin: "-50px" }}
              transition={{
                duration: 0.4,
                delay: index * 0.1,
                ease: "easeOut",
              }}
              className="relative flex items-center justify-center border p-4 bg-background rounded-xl w-40 h-20 md:w-20 lg:h-20 -mr-4 4xl:w-28 4xl:h-28"
            >
              <Image
                src={tool.lightImage}
                alt={tool.name}
                width={100}
                height={100}
                className="h-full w-full object-contain p-2 max-[406px]:p-0 max-[416px]:p-1 dark:hidden"
              />
              <Image
                src={tool.darkImage}
                alt={tool.name}
                width={100}
                height={100}
                className="hidden h-full w-full object-contain p-2 max-[406px]:p-0 max-[416px]:p-1 dark:block"
              />
              <BlurredOrb className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 dark:blur-xl blur-lg md:blur-xl dark:md:h-7 dark:md:w-7 w-7 h-7 md:h-10 md:w-10 4xl:h-14 4xl:w-14" />
            </motion.div>
          ))}
        </CardHeader>
        <CardContent className="flex flex-col gap-4 items-center justify-center w-full">
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: "-50px" }}
            transition={{
              duration: 0.5,
              delay: 0.3,
              ease: "easeOut",
            }}
            className="text-center text-3xl md:text-4xl font-aleo 4xl:text-5xl"
          >
            Integrate with your favorite tools
          </motion.p>
          <motion.p
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, margin: "-50px" }}
            transition={{
              duration: 0.5,
              delay: 0.4,
              ease: "easeOut",
            }}
            className="text-center text-muted-foreground text-lg md:text-base max-w-lg 4xl:text-3xl 4xl:max-w-4xl"
          >
            Connect seamlessly with popular platforms and services to enhance
            your workflow.
          </motion.p>
        </CardContent>
      </Card>
    </motion.div>
  );
}

"use client";
import { motion } from "motion/react";
import Image from "next/image";
import { AnimatedList } from "@/components/animated-list";
import BlurredOrb from "@/components/blurred-orb";
import { Card } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Skeleton } from "@/components/ui/skeleton";

const transcriptions = [
  {
    time: "00:20",
    text: "Hey! Thanks for hopping on. How's everything going with the new website?",
  },
  {
    time: "00:23",
    text: "Pretty good! We launched last Tuesday. Traffic's been solid so far.",
  },
  {
    time: "00:32",
    text: "That's awesome. Any issues come up?",
  },
  {
    time: "00:46",
    text: "Just one small thing—the contact form wasn't sending emails properly. But we fixed it yesterday.",
  },
];

function TranscriptionItem({ time, text }: { time: string; text: string }) {
  return (
    <div className="flex items-start 4xl:gap-8 relative">
      <span className="text-muted-foreground/60 font-mono text-xs shrink-0 pt-1 w-6 lg:w-6 xl:w-10 text-right 4xl:text-2xl">
        {time}
      </span>
      <Separator orientation="vertical" className="absolute h-[90%] top-6 left-5 lg:left-6 opacity-50 dark:bg-white/60"/>
      <div className="relative pl-6 pb-6 last:pb-0">
        <p className="text-foreground/80 leading-relaxed text-xs lg:text-sm 4xl:text-2xl">
          {text}
        </p>
